questions.texte:
Analyser le programme C ci-dessous (incomplet). Corriger les erreurs et compléter les lignes manquantes pour qu'il réalise la même fonction que la question 2.

```c
#include <stdio.h>
int main() {
    float Notes[15];
    int i, compteur;
    float somme, moyenne;
    // Ligne 1 : Initialiser somme à 0
    // Ligne 2 : Initialiser compteur à 0
    for (i = 0; i <= 15; i++) {
        printf("Note %d : ", i);
        scanf("%f", Notes[i]);
        somme = somme + Notes[i];
    }
    moyenne = somme / 15;
    // Ligne 3 : Afficher la moyenne
    for (i = 0; i < 15; i++) {
        if (Notes[i] >= 10)
            compteur++; // Ligne 4 : Que fait cette instruction ?
    }
    printf("Moyenne: %f, Compteur: %d", moyenne, compteur);
    return 0;
}
```

questions.reponse:
**Erreurs corrigées et lignes complétées :**

- **Erreur 1 :** La condition du for est `i <= 15` alors que le tableau va de 0 à 14. Il faut `i < 15`.
- **Erreur 2 :** `scanf("%f", Notes[i])` doit être `scanf("%f", &Notes[i])` car `scanf` a besoin de l'adresse mémoire.
- **Ligne 1 :** `somme = 0;`
- **Ligne 2 :** `compteur = 0;`
- **Ligne 3 :** `printf("La moyenne est : %.2f\n", moyenne);`
- **Ligne 4 :** Cette instruction incrémente `compteur` de 1 à chaque fois que la note est >= 10. Elle permet de compter les élèves ayant la moyenne.

**Programme corrigé :**
```c
#include <stdio.h>
int main() {
    float Notes[15];
    int i, compteur;
    float somme, moyenne;
    somme = 0;
    compteur = 0;
    for (i = 0; i < 15; i++) {
        printf("Note %d : ", i+1);
        scanf("%f", &Notes[i]);
        somme = somme + Notes[i];
    }
    moyenne = somme / 15;
    printf("La moyenne est : %.2f\n", moyenne);
    for (i = 0; i < 15; i++) {
        if (Notes[i] >= 10)
            compteur++;
    }
    printf("Moyenne: %.2f, Compteur: %d\n", moyenne, compteur);
    return 0;
}
```

**Solution :** On ajoute deux variables `max` et `min`. On initialise `max` à la première note (ou à 0) et `min` à la première note (ou à 20). Dans la boucle de saisie, on compare chaque note avec `max` et `min`.

```c
#include <stdio.h>

int main() {
    const int N = 15;
    float Notes[15];
    int i, compteur = 0;
    float somme = 0, moyenne, max, min;

    // Saisie de la première note pour initialiser max et min
    printf("Entrer la note de l'élève 1 : ");
    scanf("%f", &Notes[0]);
    somme = Notes[0];
    max = Notes[0];
    min = Notes[0];

    // Saisie des autres notes
    for (i = 1; i < N; i++) {
        printf("Entrer la note de l'élève %d : ", i+1);
        scanf("%f", &Notes[i]);
        somme = somme + Notes[i];
        if (Notes[i] > max) max = Notes[i];
        if (Notes[i] < min) min = Notes[i];
    }

    // Affichage des notes
    printf("\nListe des notes :\n");
    for (i = 0; i < N; i++) {
        printf("%.2f\t", Notes[i]);
    }

    // Calcul de la moyenne
    moyenne = somme / N;
    printf("\nMoyenne de la classe : %.2f\n", moyenne);
    printf("Note maximale : %.2f\n", max);
    printf("Note minimale : %.2f\n", min);

    // Comptage des élèves ayant la moyenne
    for (i = 0; i < N; i++) {
        if (Notes[i] >= 10) compteur++;
    }

    printf("Nombre d'élèves ayant la moyenne : %d\n", compteur);

    return 0;
}
```

**Explication :** Le maximum et le minimum sont trouvés en parcourant une seule fois le tableau. On initialise avec la première note pour éviter les valeurs par défaut.
